import { useState } from "react";//תופס את מה שהמשתמש מקליד
import { useDispatch, useSelector } from "react-redux";//שולח את הפונקציה לסטור
import { login } from "../redux/userSlice"; // הפעולה שיצרתי מקודם
import { useNavigate } from "react-router-dom";//ניווט בין דפים

function Login() {
    // 1. יצירת משתני יוזסטייט
    const [username, setUsername] = useState("");
    const [password, setPassword] = useState("");

    const admin = useSelector(state => state.user.admin);

    // הגדרת דיספאצ' וינויגיט
    const dispatch = useDispatch();
    const navigate = useNavigate();

    //בדיקה לפני שליחה לפונקציה לוגאין
    const handleSubmit = (e) => {
        // 4. מונע את ברירת המחדל של הטופס
        e.preventDefault();

        //אם אתה מנהל
        if (username == admin.name && password == admin.password) {
            dispatch(login({ customerName: "admin", role: "admin" }));
            alert("ברוך הבא מנהל");
            navigate('/shop');
        }
        //אם אתה משתמש רגיל
        else {
            dispatch(login({ customerName: username, password: password, role: "user" }));
            navigate('/shop');
        }
    };

    return (
        // כאן יבוא ה-JSX (הטופס)
        <form onSubmit={handleSubmit}>
            <input type="text" placeholder="שם משתמש" value={username} onChange={(e) => setUsername(e.target.value)}/>
            <input type="password" placeholder="סיסמה" value={password} onChange={(e) => setPassword(e.target.value)}/>
            <button type="submit">התחבר</button>

        </form>

    );
}

export default Login;
